    27→// NotifyWorker is a River worker that processes NotifyJobArgs.
    28→// It looks up the release, finds all source-level subscriptions, resolves
    29→// the notification channel for each, and dispatches via the appropriate sender.
    30→// After sending notifications, it checks the project's agent rules and
    31→// auto-triggers an agent run if the version criteria are met.
    32→type NotifyWorker struct {
    33→	river.WorkerDefaults[queue.NotifyJobArgs]
    34→	store   NotifyStore
    35→	senders map[string]Sender
    36→}
    37→
    38→// NewSenders returns the default sender map for webhook, Slack, and Discord.
    39→func NewSenders() map[string]Sender {
    40→	return map[string]Sender{
    41→		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    42→		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    43→		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    44→	}
    45→}
    46→
    47→// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    48→func NewNotifyWorker(store NotifyStore) *NotifyWorker {
    49→	return &NotifyWorker{
    50→		store:   store,
    51→		senders: NewSenders(),
    52→	}
    53→}
    54→
    55→// Work processes a notify job: fetches the release, resolves subscriptions,
    56→// sends notifications to all matching channels, and checks agent rules to
    57→// auto-trigger agent runs when version criteria are met.
    58→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    59→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    60→	if err != nil {
    61→		return fmt.Errorf("get release: %w", err)
    62→	}
    63→
    64→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
    65→	if err != nil {
    66→		return fmt.Errorf("list subscriptions: %w", err)
    67→	}
    68→
    69→	for _, sub := range subs {
    70→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
    71→		if err != nil {
    72→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
    73→			continue
    74→		}
    75→
    76→		sender, ok := w.senders[ch.Type]
    77→		if !ok {
    78→			slog.Warn("unknown channel type", "type", ch.Type)
    79→			continue
    80→		}
    81→
    82→		msg := Notification{
    83→			Title:   fmt.Sprintf("New release: %s", release.Version),
    84→			Body:    string(release.RawData),
    85→			Version: release.Version,
    86→		}
    87→
    88→		if err := sender.Send(ctx, ch, msg); err != nil {
    89→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
    90→		}
    91→	}
    92→
    93→	// Check agent rules and auto-trigger if criteria are met.
    94→	w.checkAgentRules(ctx, release, job.Args.SourceID)
    95→
    96→	return nil
    97→}
